import asyncio
import datetime
from dataclasses import dataclass
from typing import Literal

GracePeriodPhase = Literal["early", "mid", "late", "expired"]

@dataclass
class GracePeriodState:
    deprecated_date: datetime.date
    sunset_date: datetime.date

    @property
    def days_remaining(self) -> int:
        return (self.sunset_date - datetime.date.today()).days

    @property
    def phase(self) -> GracePeriodPhase:
        total = (self.sunset_date - self.deprecated_date).days
        elapsed = (datetime.date.today() - self.deprecated_date).days
        if elapsed < 0:
            return "early"
        pct = elapsed / total
        if pct < 0.33:
            return "early"
        elif pct < 0.67:
            return "mid"
        elif pct < 1.0:
            return "late"
        return "expired"

    @property
    def latency_penalty_ms(self) -> int:
        """
        Latency penalty escalates as sunset approaches.
        This creates a measurable operational incentive to migrate
        without causing service errors.
        """
        phase_penalties = {
            "early": 0,
            "mid":   200,
            "late":  500,
            "expired": 0,   # expired → hard error instead
        }
        return phase_penalties[self.phase]

async def serve_deprecated_version(
    handler,
    request,
    grace_state: GracePeriodState,
) -> dict:
    phase = grace_state.phase

    if phase == "expired":
        return {
            "error": "DEPRECATED_VERSION_SUNSET",
            "message": (
                f"This version was sunset on {grace_state.sunset_date}. "
                "Migrate to the current version. "
                "Migration guide: https://wiki/migration"
            ),
            "migration_url": "https://wiki/migration",
        }

    penalty = grace_state.latency_penalty_ms
    if penalty > 0:
        await asyncio.sleep(penalty / 1000)

    result = await handler(request)

    result["_deprecation_warning"] = {
        "days_remaining": grace_state.days_remaining,
        "phase": phase,
        "message": (
            f"This version is deprecated. "
            f"{grace_state.days_remaining} days remaining before sunset. "
            "Migrate now to avoid service interruption."
        ),
    }
    return result
